// OneDrive Delta-Ergebnisse verarbeiten
// Erkennt: neue Dateien, geaenderte Dateien, geloeschte Dateien

const deltaResponse = $input.first().json;
const items = deltaResponse.body?.value || [];
const results = [];

for (const item of items) {
  // Ordner ueberspringen
  if (item.folder) continue;

  // Geloeschte Dateien erkennen
  if (item.deleted) {
    results.push({
      json: {
        action: 'delete',
        source: 'onedrive',
        source_id: item.id,
        file_name: item.name || 'unbekannt'
      }
    });
    continue;
  }

  // Nur unterstuetzte Dateitypen
  const name = item.name || '';
  const ext = name.split('.').pop().toLowerCase();
  if (!['pdf', 'docx', 'doc', 'txt', 'md', 'csv'].includes(ext)) continue;

  results.push({
    json: {
      action: item['@microsoft.graph.downloadUrl'] ? 'add_or_update' : 'add_or_update',
      source: 'onedrive',
      source_id: item.id,
      file_name: item.name,
      mime_type: item.file?.mimeType || '',
      download_url: item['@microsoft.graph.downloadUrl'] || '',
      modified_at: item.lastModifiedDateTime || ''
    }
  });
}

// Delta-Token fuer naechsten Lauf speichern
const deltaLink = deltaResponse.body?.['@odata.deltaLink'];
if (deltaLink) {
  const staticData = $getWorkflowStaticData('global');
  staticData.onedriveDeltaToken = deltaLink;
}

return results.length > 0 ? results : [{ json: { action: 'none' } }];

// Text aus PDF, DOCX, TXT extrahieren
// Bei gescannten PDFs: Gemini Embedding 2 (multimodal) nutzen
// Bei PDFs > 6 Seiten: In 6-Seiten-Bloecke splitten

const items = $input.all();
const results = [];

for (const item of items) {
  const fileName = item.json.file_name || item.json.name || 'unbekannt';
  const ext = fileName.split('.').pop().toLowerCase();
  let text = '';
  let pdfPages = 0;
  let pdfChunksBase64 = []; // Fuer Gemini Multimodal: PDF-Bloecke als Base64

  try {
    if (item.binary && item.binary.data) {
      const buffer = await this.helpers.getBinaryDataBuffer(item, 'data');

      if (ext === 'pdf') {
        const pdfParse = require('pdf-parse');
        const pdfData = await pdfParse(buffer);
        text = pdfData.text || '';
        pdfPages = pdfData.numpages || 0;

        // Gescanntes PDF erkannt (kaum Text)
        if (text.trim().length < 50) {
          text = '[OCR_NEEDED] ' + text;

          // PDF als Base64 fuer Gemini Embedding 2 vorbereiten
          // Bei > 6 Seiten: In Bloecke splitten
          const base64Full = buffer.toString('base64');

          if (pdfPages <= 6) {
            // Passt komplett in einen Gemini-Call
            pdfChunksBase64.push({
              data: base64Full,
              pages: `1-${pdfPages}`,
              block_index: 0
            });
          } else {
            // PDF hat > 6 Seiten → muss gesplittet werden
            // pdf-lib zum Splitten verwenden
            try {
              const { PDFDocument } = require('pdf-lib');
              const srcDoc = await PDFDocument.load(buffer);
              const totalPages = srcDoc.getPageCount();
              const blockSize = 6;

              for (let start = 0; start < totalPages; start += blockSize) {
                const end = Math.min(start + blockSize, totalPages);
                const newDoc = await PDFDocument.create();
                const pages = await newDoc.copyPages(srcDoc, 
                  Array.from({ length: end - start }, (_, i) => start + i)
                );
                pages.forEach(p => newDoc.addPage(p));
                const newPdfBytes = await newDoc.save();
                const blockBase64 = Buffer.from(newPdfBytes).toString('base64');

                pdfChunksBase64.push({
                  data: blockBase64,
                  pages: `${start + 1}-${end}`,
                  block_index: pdfChunksBase64.length
                });
              }
            } catch (splitErr) {
              // Fallback: Gesamtes PDF als einen Block senden
              // (Gemini wird die ersten 6 Seiten verarbeiten)
              pdfChunksBase64.push({
                data: base64Full,
                pages: `1-${Math.min(6, pdfPages)}`,
                block_index: 0,
                split_error: splitErr.message
              });
            }
          }
        }
      } else if (ext === 'docx' || ext === 'doc') {
        const mammoth = require('mammoth');
        const result = await mammoth.extractRawText({ buffer });
        text = result.value || '';
      } else if (['txt', 'md', 'csv'].includes(ext)) {
        text = buffer.toString('utf-8');
      }
    }
  } catch (err) {
    text = `[EXTRACTION_ERROR] ${err.message}`;
  }

  results.push({
    json: {
      ...item.json,
      extracted_text: text,
      text_length: text.length,
      pdf_pages: pdfPages,
      needs_ocr: text.startsWith('[OCR_NEEDED]'),
      pdf_chunks_base64: pdfChunksBase64, // Leer bei Text-PDFs/DOCX/TXT
      pdf_block_count: pdfChunksBase64.length
    }
  });
}

return results;

// Text in Chunks aufteilen
// Chunk-Groesse und Overlap aus .env oder Default

const text = $input.first().json.extracted_text || '';
const chunkSize = parseInt($env.CHUNK_SIZE) || 500;
const overlap = parseInt($env.CHUNK_OVERLAP) || 75;

if (!text || text.length < 10) {
  return [{ json: { skip: true, reason: 'Kein Text extrahiert' } }];
}

const chunks = [];
let start = 0;
let index = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  let chunk = text.slice(start, end);

  // Am Satzende oder Zeilenumbruch schneiden wenn moeglich
  if (end < text.length) {
    const lastPeriod = chunk.lastIndexOf('.');
    const lastNewline = chunk.lastIndexOf('\n');
    const cutPoint = Math.max(lastPeriod, lastNewline);
    if (cutPoint > chunkSize * 0.6) {
      chunk = chunk.slice(0, cutPoint + 1);
    }
  }

  const trimmed = chunk.trim();
  if (trimmed.length > 10) {
    chunks.push({
      json: {
        content: trimmed,
        chunk_index: index,
        file_name: $input.first().json.file_name || $input.first().json.name,
        source_id: $input.first().json.source_id || $input.first().json.id,
        source: $input.first().json.source || 'google_drive',
        mime_type: $input.first().json.mime_type || $input.first().json.mimeType || '',
        file_path: $input.first().json.file_path || $input.first().json.path || '',
        source_modified_at: $input.first().json.modified_at || $input.first().json.modifiedTime || new Date().toISOString()
      }
    });
    index++;
  }

  start += trimmed.length - overlap;
  if (start <= 0 && index > 0) break; // Sicherheit gegen Endlosschleife
}

return chunks;

// Embedding generieren — konfigurierbar:
// EMBEDDING_PROVIDER=ollama (lokal) oder google oder openai
//
// Bei gescannten PDFs (needs_ocr=true):
// → Automatisch gemini-embedding-2-preview nutzen (multimodal)
// → PDFs > 6 Seiten werden vorher in Bloecke gesplittet

const item = $input.first().json;
const provider = ($env.EMBEDDING_PROVIDER || 'ollama').toLowerCase();
const content = item.content;
const needsOcr = item.needs_ocr || false;
const pdfChunks = item.pdf_chunks_base64 || [];
const dim = parseInt($env.EMBEDDING_DIMENSION) || 768;
const apiKey = $env.GOOGLE_AI_API_KEY;

// --- Fall 1: Gescanntes PDF → Gemini Embedding 2 (multimodal, direkt PDF) ---
if (needsOcr && pdfChunks.length > 0 && apiKey) {
  const results = [];

  for (const block of pdfChunks) {
    try {
      const response = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-2-preview:embedContent?key=${apiKey}`,
        body: {
          model: 'models/gemini-embedding-2-preview',
          content: {
            parts: [{
              inline_data: {
                mime_type: 'application/pdf',
                data: block.data
              }
            }]
          },
          output_dimensionality: dim
        },
        json: true
      });

      const embedding = response.embedding.values;
      results.push({
        json: {
          ...item,
          content: `[PDF Seiten ${block.pages}] ${item.file_name}`,
          chunk_index: block.block_index,
          embedding: '[' + embedding.join(',') + ']',
          embedding_method: 'gemini-multimodal',
          pdf_pages_range: block.pages
        }
      });

      // Pause zwischen Bloecken (Rate Limit schonen)
      if (pdfChunks.length > 1) {
        await new Promise(r => setTimeout(r, 1000));
      }
    } catch (err) {
      results.push({
        json: { ...item, embedding_error: `Gemini Block ${block.pages}: ${err.message}` }
      });
    }
  }

  return results;
}

// --- Fall 2: Text-Dokumente → normales Embedding ---
let embedding = [];

try {
  if (provider === 'ollama') {
    const ollamaUrl = $env.OLLAMA_BASE_URL || 'http://localhost:11434';
    const model = $env.EMBEDDING_MODEL || 'nomic-embed-text';
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `${ollamaUrl}/api/embeddings`,
      body: { model, prompt: content },
      json: true
    });
    embedding = response.embedding;

  } else if (provider === 'google') {
    const model = $env.GOOGLE_EMBEDDING_MODEL || 'gemini-embedding-001';
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/${model}:embedContent?key=${apiKey}`,
      body: {
        model: `models/${model}`,
        content: { parts: [{ text: content }] },
        taskType: 'RETRIEVAL_DOCUMENT',
        output_dimensionality: dim
      },
      json: true
    });
    embedding = response.embedding.values;

  } else if (provider === 'openai') {
    const openaiKey = $env.OPENAI_API_KEY;
    const model = $env.EMBEDDING_MODEL || 'text-embedding-3-small';
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/embeddings',
      headers: { 'Authorization': `Bearer ${openaiKey}` },
      body: { model, input: content },
      json: true
    });
    embedding = response.data[0].embedding;
  }
} catch (err) {
  return [{ json: { ...item, embedding_error: err.message } }];
}

return [{
  json: {
    ...item,
    embedding: '[' + embedding.join(',') + ']',
    embedding_method: provider
  }
}];

